import tensorflow as tffrom tensorflow.keras import layersx = tf.random.normal([2, 3])print(x)# 构建网络结构input_x = tf.keras.Input(shape=(3,))hidden1 = layers.Dense(3, activation='relu')(input_x)hidden2 = layers.Dense(3, activation='relu')(hidden1)pred = layers.Dense(1, activation='sigmoid')(hidden2)# 设置模型输入与输出model = tf.keras.Model(inputs=input_x, outputs=pred)model.summary()print(model(x))